#include <stdio.h>

int main() {
    int n;
    double sum = 0.0;

    printf("Enter an integer n: ");
    scanf("%d", &n);

    for (int i = 1; i <= n; i++) {
        double numerator = 2 * i + 1;
        double denominator = i * i - 1;
        double term = numerator / denominator;

        if (i % 2 != 0) {
            sum += term;
        } else {
            sum -= term;
        }
    }

    printf("The sum of the series is: %.6f\n", sum);

    return 0;
}

#include <stdio.h>

int main(void) {
    int n;

    // Read integer n
    scanf("%d", &n);

    // Generate expanding triangle pattern
    for (int i = 1; i <= n; ++i) {
        // Print leading spaces
        for (int j = n - i; j > 0; --j) {
            printf(" ");
        }

        // Print digits
        for (int k = 0; k < i; ++k) {
            printf("%d", i);
        }

        // Move to the next line
        printf("\n");
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

#define EPSILON 1e-9

typedef struct {
    double x;
    double y;
} Point;

double distance(Point a, Point b) {
    return sqrt((a.x - b.x) * (a.x - b.x) + (a.y - b.y) * (a.y - b.y));
}

int collinear(Point p1, Point p2, Point p3) {
    double d1 = distance(p1, p2);
    double d2 = distance(p2, p3);
    double d3 = distance(p3, p1);

    return abs(d1 + d2 - d3) < EPSILON || abs(d1 + d3 - d2) < EPSILON || abs(d2 + d3 - d1) < EPSILON;
}

double heronsFormula(Point a, Point b, Point c) {
    double s = (distance(a, b) + distance(b, c) + distance(c, a)) / 2.0;
    return sqrt(s * (s - distance(a, b)) * (s - distance(b, c)) * (s - distance(c, a)));
}

int main() {
    Point points[4];
    for (int i = 0; i < 4; i++) {
        scanf("%lf %lf", &points[i].x, &points[i].y);
    }

    int count = 0;
    for (int i = 0; i < 4; i++) {
        for (int j = i + 1; j < 4; j++) {
            for (int k = j + 1; k < 4; k++) {
                if (!collinear(points[i], points[j], points[k])) {
                    double area = heronsFormula(points[i], points[j], points[k]);
                    printf("%.3f\n", area);
                    count++;
                }
            }
        }
    }

    return 0;
}

