#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int numbers[5];
    for (int i = 0; i < 5; i++) {
        numbers[i] = rand() % 10 + 1;
    }

    char hiddenNumbers[6]; // Include space for null terminator
    for (int i = 0; i < 5; i++) {
        hiddenNumbers[i * 2] = '*';
        hiddenNumbers[i * 2 + 1] = ' ';
    }
    hiddenNumbers[10] = '\0';

    int score = 0;
    char positions[6]; // Include space for null terminator
    for (int i = 0; i < 5; i++) {
        printf("Number %d: ", i + 1);
        scanf("%s", positions);

        if (positions[i * 2] == 'E' && numbers[i] % 2 == 0) {
            score += 5;
            hiddenNumbers[i * 2] = numbers[i];
        } else if (positions[i * 2] == 'O' && numbers[i] % 2 != 0) {
            score += 5;
            hiddenNumbers[i * 2] = numbers[i];
        }

        printf("Hidden Numbers: %s\n", hiddenNumbers);
    }

    printf("Final Score: %d\n", score);

    return 0;
}

