#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int numbers[5];
    for (int i = 0; i < 5; i++) {
        do {
            numbers[i] = rand() % 10 + 1;
        } while (i > 0 && numbers[i] == numbers[i - 1]);
    }

    char hiddenNumbers[6]; // Include space for null terminator
    for (int i = 0; i < 5; i++) {
        hiddenNumbers[i * 2] = '*';
        hiddenNumbers[i * 2 + 1] = ' ';
    }
    hiddenNumbers[10] = '\0';

    int score = 0;
    char positions[6]; // Include space for null terminator
    for (int i = 0; i < 5; i++) {
        printf("Number %d: ", i + 1);
        scanf("%s", positions);

        if ((positions[i * 2] == 'E' || positions[i * 2] == 'O') && numbers[i] % 2 == (positions[i * 2] - 'E')) {
            score += 5;
            hiddenNumbers[i * 2] = numbers[i];
        }

        printf("Hidden Numbers: %s\n", hiddenNumbers);
    }

    printf("Final Score: %d\n", score);

    return 0;
}

#include <stdio.h>

int main() {
    int n;
    double sum = 0.0;

    printf("Enter an integer n: ");
    scanf("%d", &n);

    for (int i = 1; i <= n; i++) {
        double numerator = 2 * i + 1;
        double denominator = i * i - 1;
        double term = numerator / denominator;

        if (i % 2 != 0) {
            sum += term;
        } else {
            sum -= term;
        }
    }

    printf("The sum of the series is: %.6f\n", sum);

    return 0;
}

