    // Generate expanding triangle pattern
    for (int i = 1; i <= n; ++i) {
        // Print leading spaces
        for (int j = n - i; j > 0; --j) {
            printf(" ");
        }

        // Print digits
        for (int k = 0; k < i; ++k) {
            printf("%d", i);
        }

        // Move to the next line
        printf("\n");
    }

    return 0;
}

